body:
when I try to skip the 'step assignment' statement in a for loop,  Iverilog reports no errors and vpp does not generate any output. In most other languages, this statement is optional, but I can not find any text in IEEE 1364-2005 regarding if this is an optional statement or not. This code works properly when building with gowin designer, I have not tested other tool chains.  This was difficult to track down.
```verilog
// Icarus Verilog version 13.0 (devel) (s20221226-524-gdc6f9f204-dirty)
//`define NOBUG

module bug_module(clk, out);
    input   wire clk;
    output  wire out;
    function automatic integer f_bug;
        input integer value;
        begin
            `ifdef NOBUG
                for( f_bug = 0; value > 0; f_bug = f_bug + 1 ) begin    // No bug
            `else
                for( f_bug = 0; value > 0; ) begin    // bug
            `endif
                if( value == 1 ) begin
                    f_bug = 0;
                    value = 0;
                end
            end
        end
    endfunction
    localparam lp = f_bug(1);
    reg r = 0;
    always @(posedge clk) r <= ~r;
    assign out = r;
endmodule

module test;
    reg     clk = 0;
    wire    out;

    bug_module UUT( .clk(clk), .out(out) );

    always #1 clk <= ~clk;
    always @(posedge clk) begin
        $display("%b", out);
    end

    initial begin
        $dumpfile("UUT.vcd");
        $dumpvars(0, test);
        $display("starting mux_tb.v");
        #8 $display( "***WARNING*** Forcing simulation to end");
        $finish;
    end
endmodule
```

